windowclass.script:
			function onInit()
				local node = getDatabaseNode();

				local tList = {
					sRecordType = "item",
					sSource = getDatabasePath(),
					sTitle = "Spell Attacks",
				};

				local w = Interface.openWindow("reference_list", getDatabasePath());
				ListManager.initSimpleListFromRecord(w, tList);

				close();
			end

			function onInit()
				local node = getDatabaseNode();

				local sRealm = DB.getValue(node, "realm", "");
				local tList = {
					sRecordType = "spelllist",
					sSource = DB.getPath(node, "lists"),
					sTitle = DB.getValue(node, "title", ""),
					aColumns = {
						{ sName = "name", sType = "string", sHeading = "List Name", nWidth=150 },
						{ sName = "class", sType = "string", sHeading = "Class", nWidth=150 },
					},
					aGroups = { { sDBField = "realm" }, { sDBField = "class" } },
					aGroupValueOrder = { string.format("%s - Open", sRealm), string.format("%s - Closed", sRealm),},
				};

				local w = Interface.openWindow("reference_groupedlist", getDatabasePath());
				ListManager.initViewFromRecord(w, tList);

				close();
			end
